struct ExprData {
    ExprData_tag tag;
    union {
        Str LiteralStr;
        Str LiteralNum;
        Bool LiteralBool;
        Str Ident;
        Declaration Decl;
        Str Assign;
        FCallData FCall;
        FunctionDef FuncDef;
        StructDefData StructDef;
        Str FieldAccess;
        Str FieldAssign;
        Str ForIn;
        Str NamedArg;
    } data;
};

